import { useCallback } from 'react';
import {
  ActivityIndicator,
  Pressable,
  type PressableProps,
  type StyleProp,
  StyleSheet,
  Text,
  type ViewStyle,
} from 'react-native';
import Animated, {
  useAnimatedStyle,
  useSharedValue,
  withSpring,
  type WithSpringConfig,
} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';
import { colors, radii, shadows, spacing } from '@/design/tokens';
import { SPRING_SOFT, withReducedMotion } from '@/design/motion';
import { useReducedMotion } from '@/design/useReducedMotion';
import { textStyles } from '@/design/typography';

type Variant = 'primary' | 'secondary';

export type ButtonProps = {
  label: string;
  onPress: PressableProps['onPress'];
  disabled?: boolean;
  loading?: boolean;
  style?: StyleProp<ViewStyle>;
  accessibilityLabel?: string;
  testID?: string;
};

// Neubrutalist press — docs/design.md §1.4 (scale 0.97 on pressIn, spring.soft),
// §1.5 (hard shadow (3,3) collapses on press). Reanimated can't animate the
// compound `shadowOffset` prop; we fade `shadowOpacity` to 0 while translating
// (3,3) so the shadow visually "collapses" into the button.
function useBaseButton(interactive: boolean) {
  const reduced = useReducedMotion();
  const pressed = useSharedValue(0);

  const animatedStyle = useAnimatedStyle(() => {
    const v = pressed.value;
    return {
      transform: [
        { translateX: v * 3 },
        { translateY: v * 3 },
        { scale: 1 - v * 0.03 },
      ],
      shadowOpacity: 1 - v,
    };
  });

  const handlePressIn = useCallback(() => {
    if (!interactive) return;
    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    pressed.value = withSpring(1, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
  }, [interactive, pressed, reduced]);

  const handlePressOut = useCallback(() => {
    if (!interactive) return;
    pressed.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
  }, [interactive, pressed, reduced]);

  return { animatedStyle, handlePressIn, handlePressOut };
}

function BaseButton({
  label,
  onPress,
  disabled = false,
  loading = false,
  variant,
  style,
  accessibilityLabel,
  testID,
}: ButtonProps & { variant: Variant }) {
  const interactive = !disabled && !loading;
  const { animatedStyle, handlePressIn, handlePressOut } = useBaseButton(interactive);

  const variantStyle = variant === 'primary' ? styles.primary : styles.secondary;
  const labelColor = disabled ? colors.ink40 : colors.ink;

  return (
    <Pressable
      onPress={interactive ? onPress : undefined}
      onPressIn={handlePressIn}
      onPressOut={handlePressOut}
      disabled={!interactive}
      accessibilityRole="button"
      accessibilityLabel={accessibilityLabel ?? label}
      accessibilityState={{ disabled: !interactive, busy: loading }}
      testID={testID}
    >
      <Animated.View
        style={[
          styles.base,
          variantStyle,
          disabled ? styles.disabled : shadows.hard,
          animatedStyle,
          style,
        ]}
      >
        {loading ? (
          <ActivityIndicator color={colors.ink} />
        ) : (
          <Text style={[textStyles.body, { color: labelColor }]}>{label}</Text>
        )}
      </Animated.View>
    </Pressable>
  );
}

export function ButtonPrimary(props: ButtonProps) {
  return <BaseButton {...props} variant="primary" />;
}

export function ButtonSecondary(props: ButtonProps) {
  return <BaseButton {...props} variant="secondary" />;
}

const styles = StyleSheet.create({
  base: {
    minHeight: 48,
    paddingHorizontal: spacing.lg,
    paddingVertical: spacing.md,
    borderRadius: radii.button,
    borderWidth: 2,
    borderColor: colors.ink,
    alignItems: 'center',
    justifyContent: 'center',
    shadowColor: colors.ink,
    shadowOpacity: 1,
    shadowRadius: 0,
  },
  primary: {
    backgroundColor: colors.cta,
  },
  secondary: {
    backgroundColor: colors.surface,
  },
  disabled: {
    backgroundColor: colors.hairline,
    borderColor: colors.ink40,
    shadowOpacity: 0,
    elevation: 0,
  },
});

// Typography — typed text-style presets for the Marketify design system.
// Mirrors docs/design.md §1.3 (font pairing table + line-height rules).
//
// Font substitution: docs/design.md names Clash Display (headings) and Satoshi (body).
// Both are Fontshare-hosted and do not ship with Expo Google Fonts; we use the explicit
// fallbacks listed in §1.3 — Outfit for display/headings, Rubik for body/caption — plus
// JetBrains Mono for monospace. Spec-sanctioned per the same section.
//
// `fontFamily` values are the string keys registered with `expo-font.useFonts` in
// `app/_layout.tsx`. They MUST match the constant names imported from
// `@expo-google-fonts/*` so RN can resolve the loaded assets by name.

import {
  Outfit_600SemiBold,
  Outfit_700Bold,
} from '@expo-google-fonts/outfit';
import {
  Rubik_500Medium,
  Rubik_700Bold,
} from '@expo-google-fonts/rubik';
import { JetBrainsMono_500Medium } from '@expo-google-fonts/jetbrains-mono';
import type { TextStyle } from 'react-native';

export const fontFamilies = {
  displayBold: 'Outfit_700Bold',
  displaySemi: 'Outfit_600SemiBold',
  bodyMedium: 'Rubik_500Medium',
  bodyBold: 'Rubik_700Bold',
  mono: 'JetBrainsMono_500Medium',
} as const;

// Map consumed by `useFonts` — values are the numeric asset handles exported by
// @expo-google-fonts/*, keys are the runtime font-family names.
export const fontAssets = {
  [fontFamilies.displayBold]: Outfit_700Bold,
  [fontFamilies.displaySemi]: Outfit_600SemiBold,
  [fontFamilies.bodyMedium]: Rubik_500Medium,
  [fontFamilies.bodyBold]: Rubik_700Bold,
  [fontFamilies.mono]: JetBrainsMono_500Medium,
} as const;

// Line heights per §1.3: 1.15 for display, ~1.55 for body. Caption + mono tighten
// to 1.4 for dense data rows.
export const textStyles = {
  display: {
    fontFamily: fontFamilies.displayBold,
    fontSize: 28,
    lineHeight: 32,
  },
  h1: {
    fontFamily: fontFamilies.displaySemi,
    fontSize: 22,
    lineHeight: 25,
  },
  h2: {
    fontFamily: fontFamilies.displaySemi,
    fontSize: 20,
    lineHeight: 23,
  },
  body: {
    fontFamily: fontFamilies.bodyMedium,
    fontSize: 15,
    lineHeight: 23,
  },
  caption: {
    fontFamily: fontFamilies.bodyMedium,
    fontSize: 13,
    lineHeight: 18,
  },
  mono: {
    fontFamily: fontFamilies.mono,
    fontSize: 14,
    lineHeight: 20,
  },
} as const satisfies Record<string, TextStyle>;

export type TextStyleToken = keyof typeof textStyles;
export type FontFamilyToken = keyof typeof fontFamilies;

